function nthUglyNumber(n, a, b, c) {
    const gcd = (x, y) => y === 0 ? x : gcd(y, x % y);

    let ab = a * b / gcd(a, b);
    let ac = a * c / gcd(a, c);
    let bc = b * c / gcd(b, c);
    let abc = a * (b * c / gcd(b, c)) / gcd(a, (b * c / gcd(b, c)));

    let left = 0, right = 2e9;
    while (left < right) {
        let mid = left + Math.floor((right - left) / 2);
        let cnt = Math.floor(mid / a) + Math.floor(mid / b) + Math.floor(mid / c) - Math.floor(mid / ab) -
                  Math.floor(mid / ac) - Math.floor(mid / bc) + Math.floor(mid / abc);
        if (cnt < n) {
            left = mid + 1;
        } else {
            right = mid;
        }
    }
    return left;
}
```

    We can solve this problem using binary search. First, we find the least common multiple of each pair of numbers (a, b), (a, c), and (b, c) as well as the least common multiple of all three numbers (a, b, c). Then, we use binary search to find the ugly number. In each iteration, we check the count of numbers divisible by a, b, or c in the range [0, mid] and compare it with our target index n. If the count is less than n, we search in the larger half of the search space, otherwise, we search in the smaller half. When our search range becomes [0,1] or left becomes equal to right, we have found the nth ugly number.

